import React, { useState, useCallback, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  SearchTextInput,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  Pagination,
} from '@linm-soft/common-components';
import { DocumentProcessingLevelPill } from '../../../components/document/DocumentProcessingLevelPill';
import { formatAssetLifecycle } from '../../../utils/documentProcessingLevelDisplay';
import { hasPermissionCode, useFixedAssetPermissions } from '../../../hooks/useFixedAssetPermissions';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import type { FixedAssetDto } from '../../../services/tscd/models';
import { formatDateLocal, formatVnd } from '../../../utils/formatters';
import { tscdPageLabels } from '../../../constants/tscdPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-tscd-list';
const PAGE_ID = 'tscd';
const PAGE_SIZE = 20;
const listLabels = tscdPageLabels.list;

const TscdListPage: React.FC = () => {
  void hasPermissionCode;
  const { canWrite } = useFixedAssetPermissions();
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [items, setItems] = useState<FixedAssetDto[]>([]);
  const [loading, setLoading] = useState(false);
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const load = useCallback(() => {
    setLoading(true);
    tscdService.getAssets({ search: search.trim() || undefined, page, pageSize: PAGE_SIZE })
      .then(setItems)
      .catch(err => dispatchAppToast(dispatch, { message: getApiErrorMessage(err, listLabels.loadError), type: 'error' }))
      .finally(() => setLoading(false));
  }, [dispatch, search, page]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const handleSearch = useCallback(() => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setPage(1);
    });
  }, [pulseSearch, searchDraft]);

  const hasNext = items.length === PAGE_SIZE;
  const totalPages = hasNext ? page + 1 : page;
  const totalCount = hasNext ? page * PAGE_SIZE + 1 : (page - 1) * PAGE_SIZE + items.length;

  const catalogToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: load,
      canAdd: canWrite,
      onAdd: canWrite ? () => navigate('/tscd/them') : undefined,
    }),
    [load, navigate, canWrite],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-search`,
        content: (
          <SearchTextInput
            label={listLabels.searchLabel}
            placeholder={listLabels.searchPlaceholder}
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            testId={`${TEST_ID}-search-text`}
          />
        ),
      },
    ],
    [searchDraft, handleSearch],
  );

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{listLabels.empty}</div>
  ) : !showTableLoading ? (
    <div className={erp.tableWrapper}>
      <table className={erp.table} data-testid={`${TEST_ID}-table`}>
        <thead>
          <tr>
            <th>{listLabels.colCode}</th>
            <th>{listLabels.colName}</th>
            <th>{listLabels.colAcquired}</th>
            <th className={erp.colRight}>{listLabels.colOriginalCost}</th>
            <th className={erp.colRight}>{listLabels.colBookValue}</th>
            <th>{listLabels.colLifecycle}</th>
          </tr>
        </thead>
        <tbody>
          {items.map(r => (
            <tr key={r.id} data-testid={`${TEST_ID}-row-${r.id}`}>
              <td>
                <button type="button" className={erp.codeLink} onClick={() => navigate(`/tscd/${r.id}`)}>
                  <code>{r.code}</code>
                </button>
              </td>
              <td>{r.name}</td>
              <td>{formatDateLocal(r.acquiredDate)}</td>
              <td className={erp.colRight}>{formatVnd(r.originalCost)}</td>
              <td className={erp.colRight}>{formatVnd(r.bookValue)}</td>
              <td>
                <DocumentProcessingLevelPill
                  label={formatAssetLifecycle(r.lifecycle)}
                  compact
                  testId={`${TEST_ID}-lifecycle-${r.id}`}
                />
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="catalog"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: listLabels.title,
          titleIconClass: 'fas fa-building',
          pageId: PAGE_ID,
        }}
        catalogToolbar={catalogToolbar}
        listTitle={listLabels.listTitle}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={
          (page > 1 || hasNext) ? (
            <div className={erp.paginationRow}>
              <Pagination
                currentPage={page}
                totalPages={totalPages}
                totalCount={totalCount}
                pageSize={PAGE_SIZE}
                onPageChange={setPage}
              />
            </div>
          ) : undefined
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default TscdListPage;
